function isAuthError(err) {
  const msg = String(err).toLowerCase();
  return msg.includes("invalid_grant") || msg.includes("token has been expired or revoked") || msg.includes("invalid credentials") || msg.includes("unauthorized");
}
__name(isAuthError, "isAuthError");
